import React, { useState } from 'react';
import { FileUp, Scissors, Trash2, Layers, CheckSquare, Square, Eye } from 'lucide-react';

export default function App() {
  const [file, setFile] = useState(null);
  const [pages, setPages] = useState(Array.from({ length: 12 }, (_, i) => ({ id: i + 1, selected: false })));
  const [previewPage, setPreviewPage] = useState(null);

  const togglePage = (id) => {
    setPages(pages.map(p => p.id === id ? { ...p, selected: !p.selected } : p));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 p-4 md:p-8 font-sans">
      <header className="max-w-5xl mx-auto mb-12">
        <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">PDF Architect</h1>
        <p className="text-slate-400 mt-2">Professional-grade PDF splitting and page management.</p>
      </header>

      <main className="max-w-5xl mx-auto space-y-8">
        {!file ? (
          <div className="border-2 border-dashed border-slate-800 rounded-3xl p-12 text-center bg-slate-900/50 hover:bg-slate-900 transition-colors cursor-pointer group">
            <input type="file" className="hidden" id="file-upload" onChange={() => setFile("document.pdf")} />
            <label htmlFor="file-upload" className="cursor-pointer">
              <div className="w-16 h-16 bg-blue-500/10 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <FileUp className="w-8 h-8 text-blue-400" />
              </div>
              <h3 className="text-xl font-semibold">Upload PDF Document</h3>
              <p className="text-slate-500 mt-2">Drag & drop or click to browse</p>
            </label>
          </div>
        ) : (
          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-2xl">
            <div className="flex items-center justify-between mb-8 pb-6 border-b border-slate-800">
              <div className="flex items-center gap-4">
                <div className="bg-emerald-500/10 p-3 rounded-xl">
                  <Layers className="text-emerald-400" />
                </div>
                <div>
                  <h2 className="font-bold text-lg">document.pdf</h2>
                  <p className="text-sm text-slate-400">{pages.length} pages detected</p>
                </div>
              </div>
              <button onClick={() => setFile(null)} className="text-red-400 hover:text-red-300 flex items-center gap-2">
                <Trash2 size={18} /> Remove
              </button>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {pages.map((page) => (
                <div 
                  key={page.id} 
                  className={`group relative aspect-[3/4] rounded-xl border-2 transition-all overflow-hidden ${page.selected ? 'border-emerald-500 bg-emerald-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-600'}`}
                >
                  <div className="absolute top-2 left-2 z-20 cursor-pointer" onClick={() => togglePage(page.id)}>
                    {page.selected ? <CheckSquare className="text-emerald-400" /> : <Square className="text-slate-600" />}
                  </div>

                  <button 
                    onClick={() => setPreviewPage(page.id)}
                    className="absolute top-2 right-2 z-20 bg-slate-950/50 p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-blue-600"
                  >
                    <Eye size={14} />
                  </button>

                  <div className="absolute inset-0 flex items-center justify-center font-bold text-slate-600 group-hover:text-slate-500 transition-colors">
                    Page {page.id}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-8 flex justify-end">
              <button className="bg-blue-600 hover:bg-blue-500 px-8 py-3 rounded-xl font-medium flex items-center gap-2 transition-all hover:shadow-[0_0_20px_-5px_rgba(37,99,235,0.5)]">
                <Scissors size={20} /> Split Selected Pages
              </button>
            </div>
          </div>
        )}
      </main>

      {previewPage && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4" onClick={() => setPreviewPage(null)}>
          <div className="bg-slate-900 p-8 rounded-2xl max-w-lg w-full border border-slate-700 animate-in fade-in zoom-in duration-200">
            <h3 className="text-2xl font-bold mb-4">Preview Page {previewPage}</h3>
            <div className="aspect-[3/4] bg-white rounded-lg flex items-center justify-center text-slate-900 font-bold text-4xl shadow-inner">
              CONTENT OF PAGE {previewPage}
            </div>
            <button onClick={() => setPreviewPage(null)} className="mt-6 w-full py-3 bg-slate-800 rounded-xl hover:bg-slate-700">Close</button>
          </div>
        </div>
      )}
    </div>
  );
}
